// Pick the leads worth scanning for a follow-up gap.
// Rules out anything that isn't an open, contactable lead:
//   - no email on file                  -> nothing to follow up on
//   - archived                           -> off the board
//   - stage won / lost                   -> closed
//   - seq_status 'replied'               -> they're already engaged
//   - snoozed into the future            -> the user chose to wait
// Firestore runQuery returns one item per doc; some carry only a readTime -> skip those.

function fsVal(field) {
  if (!field) return null;
  if (field.stringValue    !== undefined) return field.stringValue;
  if (field.integerValue   !== undefined) return Number(field.integerValue);
  if (field.booleanValue   !== undefined) return field.booleanValue;
  if (field.timestampValue !== undefined) return field.timestampValue;
  if (field.nullValue      !== undefined) return null;
  return null;
}

const CLOSED = ['won', 'lost'];
const today  = new Date().toISOString().slice(0, 10);
const out = [];

// Flatten whether the HTTP node split the runQuery array into items or returned it whole.
let rows = [];
for (const it of $input.all()) { const j = it.json; if (Array.isArray(j)) rows.push(...j); else rows.push(j); }

for (const row of rows) {
  const d = row && row.document;
  if (!d || !d.name) continue;
  const f = d.fields || {};
  const id    = d.name.split('/').pop();
  const email = (fsVal(f.email) || '').trim().toLowerCase();
  if (!email) continue;
  if (fsVal(f.archived) === true) continue;
  if (CLOSED.includes(fsVal(f.stage) || 'cold')) continue;
  if (fsVal(f.seq_status) === 'replied') continue;
  const snooze = fsVal(f.followup_snooze_until) || fsVal(f.snooze_until);
  if (snooze && String(snooze) >= today) continue;

  out.push({ json: {
    leadId:    id,
    email,
    company:   fsVal(f.company)   || '',
    createdAt: fsVal(f.createdAt) || null
  }});
}

return out;

// Find the most recent contact date for this lead in either direction
// (received from them OR sent to them) and turn it into follow-up fields.
// Graph $search returns messages across all folders, relevance-ordered, so we
// scan the hits and keep the newest receivedDateTime / sentDateTime we see.
// No email history -> fall back to the lead's creation date so a lead that has
// sat untouched since it was added still surfaces. Rule: cold at >= 3 days.

const FOLLOWUP_DAYS = 3;
const resp = $input.first().json || {};
const msgs = Array.isArray(resp.value) ? resp.value : [];
const loop = $('Loop leads').item.json;

let maxMs = null;
let everContacted = false;
for (const m of msgs) {
  for (const k of ['receivedDateTime', 'sentDateTime']) {
    const t = m && m[k] ? Date.parse(m[k]) : NaN;
    if (!isNaN(t)) { everContacted = true; if (maxMs === null || t > maxMs) maxMs = t; }
  }
}

let fellBackToCreated = false;
if (maxMs === null && loop.createdAt) {
  const t = Date.parse(loop.createdAt);
  if (!isNaN(t)) { maxMs = t; fellBackToCreated = true; }
}

let days = maxMs === null ? null : Math.floor((Date.now() - maxMs) / 86400000);
if (days !== null && days < 0) days = 0;
const due      = days !== null && days >= FOLLOWUP_DAYS;
const lastDate = maxMs === null ? null : new Date(maxMs).toISOString().slice(0, 10);

const fields = {
  last_contact_date:   lastDate === null ? { nullValue: null } : { stringValue: lastDate },
  days_since_contact:  days === null     ? { nullValue: null } : { integerValue: String(days) },
  followup_due:        { booleanValue: !!due },
  followup_contacted:  { booleanValue: !!everContacted },
  followup_checked_at: { stringValue: new Date().toISOString() }
};

return [{ json: { leadId: loop.leadId, days, due, fellBackToCreated, patchBody: { fields } } }];
